using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace WeatherMcpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The SDK discovers all [McpServerTool] methods in classes marked [McpServerToolType].
/// Constructor parameters are resolved from DI — here, HttpClient is injected
/// via the named IHttpClientFactory registration in Program.cs.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool, Description("Get the current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")]  double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

        var result = await _http.GetFromJsonAsync<WeatherResponse>(url, cancellationToken)
            ?? throw new InvalidOperationException("Empty response from weather API.");

        var c = result.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h, Humidity: {c.Humidity}%";
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")]  double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var result = await _http.GetFromJsonAsync<ForecastResponse>(url, cancellationToken)
            ?? throw new InvalidOperationException("Empty response from weather API.");

        var d = result.Daily;
        var lines = d.Time.Select((date, i) =>
            $"{date}: {d.MinTemp[i]}°C – {d.MaxTemp[i]}°C");

        return string.Join('\n', lines);
    }
}

// --- DTOs for Open-Meteo JSON responses ---

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")]       double Temperature,
    [property: JsonPropertyName("wind_speed_10m")]       double WindSpeed,
    [property: JsonPropertyName("relative_humidity_2m")] double Humidity);

public record ForecastResponse(
    [property: JsonPropertyName("daily")] DailyForecast Daily);

public record DailyForecast(
    [property: JsonPropertyName("time")]               string[] Time,
    [property: JsonPropertyName("temperature_2m_max")] double[] MaxTemp,
    [property: JsonPropertyName("temperature_2m_min")] double[] MinTemp);

