using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using WeatherMcpServer;

var builder = Host.CreateApplicationBuilder(args);

builder.Services
    // Register a named HttpClient for WeatherTools.
    // The SDK resolves constructor params from DI; IHttpClientFactory
    // creates the HttpClient that gets injected into WeatherTools.
    .AddHttpClient<WeatherTools>(client =>
    {
